proof:
by_contra h;
obtain ⟨a, ha⟩ : ∃ a, |g a| > 1 := by
  aesop;
have h_seq : ∀ n : ℕ, ∃ x_n : ℝ, |f x_n| ≥ |f (Classical.choose (not_forall.mp h₁))| * |g a|^n := by
  intro n
  induction' n with n ih
  · use Classical.choose (not_forall.mp h₁)
    simp
  · obtain ⟨x_n, hx_n⟩ := ih
    have h_max : max (|f (x_n + a)|) (|f (x_n - a)|) ≥ |f x_n| * |g a| := by
      have := h₀ x_n a; cases abs_cases ( f ( x_n + a ) ) <;> cases abs_cases ( f ( x_n - a ) ) <;> cases abs_cases ( f x_n ) <;> cases abs_cases ( g a ) <;> nlinarith [ le_max_left |f ( x_n + a )| |f ( x_n - a )|, le_max_right |f ( x_n + a )| |f ( x_n - a )| ] ;
    cases max_cases |f ( x_n + a )| |f ( x_n - a )| <;> [ exact ⟨ x_n + a, by rw [ pow_succ' ] ; nlinarith [ abs_nonneg ( f ( Classical.choose ( not_forall.mp h₁ ) ) ) ] ⟩ ; exact ⟨ x_n - a, by rw [ pow_succ' ] ; nlinarith [ abs_nonneg ( f ( Classical.choose ( not_forall.mp h₁ ) ) ) ] ⟩ ];
obtain ⟨n, hn⟩ : ∃ n : ℕ, |f (Classical.choose (not_forall.mp h₁))| * |g a|^n > 1 := by
  have h_exp : Filter.Tendsto (fun n : ℕ => |f (Classical.choose (not_forall.mp h₁))| * |g a|^n) Filter.atTop Filter.atTop := by
    exact Filter.Tendsto.const_mul_atTop ( abs_pos.mpr ( Classical.choose_spec ( not_forall.mp h₁ ) ) ) ( tendsto_pow_atTop_atTop_of_one_lt ha );
  exact ( h_exp.eventually_gt_atTop 1 ) |> fun h => h.exists;
obtain ⟨ x_n, hx_n ⟩ := h_seq n ; linarith [ h₂ x_n ]

